import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { api } from "../api";

export default function Home({ user, onLogout }) {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    api.getProducts()
      .then(data => setProducts(data))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("Удалить товар?")) return;
    try {
      await api.deleteProduct(id);
      setProducts(prev => prev.filter(p => p.id !== id));
    } catch (err) {
      alert("Ошибка удаления: " + (err?.response?.data?.error || err.message));
    }
  };

  return (
    <div className="container">
      <div className="header-toolbar">
        <h1>Интернет-магазин корейской косметики</h1>
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <button className="btn btn--primary create-btn" onClick={() => navigate("/create")}>+ Создать товар</button>
          <span style={{ margin: "0 8px" }}>{user.email}</span>
          <button className="btn" onClick={onLogout}>Выйти</button>
        </div>
      </div>

      {loading ? (
        <div>Загрузка товаров...</div>
      ) : (
        <div className="grid">
          {products.map(p => (
            <div key={p.id} className="card">
              <img src={p.image} alt={p.name} />
              <h3>{p.name}</h3>
              <p><b>Категория:</b> {p.category}</p>
              <p>{p.description}</p>
              <p><b>Цена:</b> {p.price} ₽</p>
              <p><b>В наличии:</b> {p.stock}</p>
              <p>⭐ {p.rating}</p>
              <div className="card-actions">
                <Link to={`/product/${p.id}`} className="btn">Подробнее</Link>
                <button className="btn edit-btn" onClick={() => navigate(`/edit/${p.id}`)}>Редактировать</button>
                <button className="btn danger-btn" onClick={() => handleDelete(p.id)}>Удалить</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
